from dataclasses import dataclass, field
from datetime import date
from enum import Enum

class ComplianceStatus(str, Enum):
    MET        = "met"
    NEAR_MISS  = "near_miss"   # >90% but <100% of SLA window used
    MISSED     = "missed"

@dataclass
class TicketSLASummary:
    ticket_id: str
    priority: str
    opened_date: date
    first_response_status: ComplianceStatus
    resolution_status: ComplianceStatus | None   # None if still open
    breach_duration_minutes: float | None
    root_cause: str | None
    credit_applied_pct: float

@dataclass
class MonthlyAccountReport:
    account_id: str
    account_name: str
    report_month: date            # first day of the month
    tickets: list[TicketSLASummary]

    def first_response_compliance(self) -> dict[str, float]:
        by_priority: dict[str, list[bool]] = {}
        for t in self.tickets:
            by_priority.setdefault(t.priority, [])
            by_priority[t.priority].append(
                t.first_response_status == ComplianceStatus.MET
            )
        return {
            p: sum(vals) / len(vals) if vals else 1.0
            for p, vals in by_priority.items()
        }

    def total_credit_pct(self) -> float:
        return sum(t.credit_applied_pct for t in self.tickets)

    def breached_tickets(self) -> list[TicketSLASummary]:
        return [t for t in self.tickets if t.first_response_status == ComplianceStatus.MISSED]

    def near_miss_tickets(self) -> list[TicketSLASummary]:
        return [t for t in self.tickets if t.first_response_status == ComplianceStatus.NEAR_MISS]

    def executive_summary(self) -> str:
        compliance = self.first_response_compliance()
        breaches = self.breached_tickets()
        lines = [f"SLA Report: {self.account_name} — {self.report_month.strftime('%B %Y')}"]
        for priority, rate in sorted(compliance.items()):
            lines.append(f"  {priority} first-response compliance: {rate*100:.1f}%")
        if breaches:
            lines.append(f"  Breaches: {len(breaches)} ({', '.join(t.ticket_id for t in breaches)})")
            lines.append(f"  Total credit applied: {self.total_credit_pct()*100:.1f}%")
        else:
            lines.append("  No SLA breaches this month.")
        return "\n".join(lines)

from dataclasses import dataclass
from datetime import date

@dataclass
class ReportValidationResult:
    passed: bool
    errors: list[str]
    warnings: list[str]

def validate_monthly_report(report, expected_ticket_count: int) -> ReportValidationResult:
    """
    Validates a MonthlyAccountReport before customer delivery.
    Returns errors (blocking) and warnings (require manual review).
    """
    errors: list[str] = []
    warnings: list[str] = []

    # Count check: total tickets must match expected (from ticket system)
    if len(report.tickets) != expected_ticket_count:
        errors.append(
            f"Ticket count mismatch: report has {len(report.tickets)}, "
            f"ticket system shows {expected_ticket_count}"
        )

    # Compliance rate sanity check: should be between 0 and 1
    for priority, rate in report.first_response_compliance().items():
        if not (0.0 <= rate <= 1.0):
            errors.append(f"Compliance rate for {priority} out of range: {rate}")

    # Credit check: no individual ticket should have credit > 20%
    for t in report.tickets:
        if t.credit_applied_pct > 0.20:
            errors.append(
                f"Ticket {t.ticket_id} credit {t.credit_applied_pct*100:.0f}% "
                f"exceeds 20% cap — check calculation"
            )

    # Near-miss count: warn if > 10% of tickets are near misses
    near_miss_rate = len(report.near_miss_tickets()) / max(len(report.tickets), 1)
    if near_miss_rate > 0.10:
        warnings.append(
            f"Near-miss rate {near_miss_rate*100:.0f}% is high — "
            f"consider noting this in the executive summary"
        )

    # Open tickets: warn if any P0/P1 tickets are still open at report time
    open_critical = [
        t for t in report.tickets
        if t.resolution_status is None and t.priority in ("P0", "P1")
    ]
    if open_critical:
        warnings.append(
            f"{len(open_critical)} P0/P1 tickets still open — "
            f"confirm status before sending report"
        )

    return ReportValidationResult(
        passed=len(errors) == 0,
        errors=errors,
        warnings=warnings,
    )
